bool isAdult = true;
bool hasID = false;

// C-style (common):
cout << (isAdult && hasID) << endl;  // 0 (false)
cout << (isAdult || hasID) << endl;  // 1 (true)
cout << (!isAdult) << endl;          // 0 (false)

// C++ keyword style (valid but uncommon):
cout << (isAdult and hasID) << endl;  // 0
cout << (isAdult or hasID) << endl;   // 1
cout << (not isAdult) << endl;        // 0

