examples.code:
#include <iostream>
using namespace std;
int main() {
    int score = 82;

    if (score >= 90) {
        cout << "A" << endl;
    } else if (score >= 80) {
        cout << "B" << endl;
    } else if (score >= 70) {
        cout << "C" << endl;
    } else {
        cout << "F" << endl;
    }
    return 0;
}
// Output: B

// Classic C++ (variable leaks into outer scope):
int val = getValue();
if (val > 0) { use(val); }
// val still exists here

// C++17: init inside if (cleaner):
if (int val = getValue(); val > 0) {
    use(val);
}
// val doesn't exist after the if block

// Range-based for loop (full detail in Level 3):
vector<int> scores = {90, 72, 85, 60};

for (int s : scores) {  // for each score
    if (s >= 80) {
        cout << s << " is great!" << endl;
    } else {
        cout << s << " needs work" << endl;
    }
}

