int command = 2;
switch (command) {
    case 1: cout << "Start" << endl; break;
    case 2: cout << "Stop" << endl;  break;
    case 3: cout << "Reset" << endl; break;
    default: cout << "Unknown" << endl;
}
// Output: Stop

int x = 1;
switch (x) {
    case 1:
        cout << "One" << endl;
        [[fallthrough]]; // intentional! suppress warning
    case 2:
        cout << "Two or fell from One" << endl;
        break;
    case 3:
        cout << "Three" << endl;
}

int a = 7, b = 3;
auto max = (a > b) ? a : b;  // auto deduces int
cout << max << endl;           // 7

bool flag = true;
string msg = flag ? "on" : "off";
cout << msg << endl;  // on

// Ternary in cout:
int score = 80;
cout << (score >= 60 ? "Pass" : "Fail") << endl;

